                                        pcall(function() for _, c in pairs(getconnections(t.Activated))         do c:Fire() end end)
                                        pcall(function()
                                            for _, c in pairs(getconnections(t.InputBegan)) do
                                                c:Fire({UserInputType=Enum.UserInputType.MouseButton1, UserInputState=Enum.UserInputState.Begin})
                                                c:Fire({UserInputType=Enum.UserInputType.Touch,        UserInputState=Enum.UserInputState.Begin})
                                            end
                                        end)
                                    end
                                end
                            end
                            task.wait(0.1)
                            if not char:FindFirstChildOfClass("Tool") and backpack and hum then
                                for _, tool in pairs(backpack:GetChildren()) do
                                    if tool:IsA("Tool") and M.validWeights[tool.Name] then
                                        hum:EquipTool(tool)
                                        break
                                    end
                                end
                            end
                        else
                            currentTool:Activate()
                            if getconnections then
                                for _, c in pairs(getconnections(currentTool.Activated)) do c:Fire() end
                            end
                        end
                    end)
                    pcall(function()
                        local kickUpgrades = PlayerGui:FindFirstChild("KickUpgrades")
                        if not kickUpgrades then return end
                        for _, bonus in pairs(kickUpgrades:GetChildren()) do
                            if bonus.Name == "Bonus" or bonus.Name == "PopBonus" then
                                if bonus.Visible then
                                    if not bonus:GetAttribute("AutoClicked") then
                                        bonus:SetAttribute("AutoClicked", true)
                                        task.spawn(function()
