WebhookGroup:AddButton({
    Text = "测试 Webhook ",
    Func = function()
        if not DiscordState.WebhookURL or DiscordState.WebhookURL == "" then
            Library:Notify({ Title = "Discord", Description = "尚未设置 Webhook URL。", Time = 3 })
            return
        end
        local HttpService = game:GetService("HttpService")
        local payload = HttpService:JSONEncode({
            content  = "@everyone\n✅ **COMBOWICK** Webhook 测试成功！\n👤 **玩家：** " .. player.Name,
            username = "COMBOWICK Alert",
        })
        local ok, err = pcall(function()
            request({
                Url     = DiscordState.WebhookURL,
                Method  = "POST",
                Headers = { ["Content-Type"] = "application/json" },
                Body    = payload,
            })
        end)
        if ok then
            Library:Notify({ Title = "Discord", Description = "测试通知已成功发送。", Time = 3 })
        else
            Library:Notify({ Title = "Discord", Description = "错误：" .. tostring(err), Time = 5 })
        end
    end,
})

